/**
 * @fileoverview ClipBox events — centralised event binding via AbortController.
 * @module module/ClipBox/events
 */

import razyui from '../../index.js';
import { SEL } from './constants.js';
import { BLUR_DELAY } from './constants.js';

/**
 * Bind all ClipBox events on the container and inner text input.
 * Returns an AbortController whose `.abort()` tears down every listener.
 *
 * @param {object} ctx
 * @param {HTMLElement}       ctx.container   — clip-box root element
 * @param {HTMLInputElement}  ctx.textInput   — inner text input
 * @param {object}            ctx.stateRef    — reactive state reference
 * @param {Function}          ctx.setState    — reactive state setter
 * @param {object}            ctx.config      — merged config
 * @param {Function}          ctx.addChip     — (value, label) => boolean
 * @param {Function}          ctx.fireRemove  — (chip) => void
 * @param {Function}          ctx.fireChange  — () => void
 * @param {Function}          ctx.hideFloating — () => void
 * @param {Function}          ctx.onSearchInput — () => void
 * @param {Function}          ctx.openDarkroom  — () => void
 * @param {Function}          ctx.closeDarkroom — () => void
 * @param {Function}          ctx.getDarkroom   — () => HTMLElement|null
 * @returns {AbortController}
 */
export function bindEvents(ctx) {
    const {
        container, textInput, stateRef, setState, config,
        addChip, fireRemove, fireChange, hideFloating,
        onSearchInput, openDarkroom, closeDarkroom, getDarkroom,
    } = ctx;

    const ac = new AbortController();
    const opts = { signal: ac.signal };

    const $container = razyui(container);
    const $textInput = razyui(textInput);

    // Container click → focus input (or open darkroom in compact mode)
    $container.on('click', (e) => {
        if (e.target.closest(SEL.REMOVE)) return;
        if (config.compact && !getDarkroom()) {
            openDarkroom();
            return;
        }
        textInput.focus();
    }, opts);

    // Keyboard input
    $textInput.on('keydown', (e) => {
        if (stateRef.disabled || stateRef.readonly) return;

        if (e.key === 'Enter') {
            e.preventDefault();
            if (!config.url) {
                // Offline mode: commit typed value
                const val = textInput.value.trim();
                if (val) {
                    addChip(val, val, val);
                    textInput.value = '';
                }
            }
            // Remote mode: Enter does nothing (user must pick from list)
            hideFloating();
        } else if (e.key === 'Backspace' && textInput.value === '') {
            // Remove last chip
            const chips = [...stateRef.chips];
            if (chips.length) {
                const removed = chips.pop();
                setState({ chips });
                fireRemove(removed);
                fireChange();
            }
        } else if (e.key === 'Escape') {
            if (getDarkroom()) {
                closeDarkroom();
                return;
            }
            hideFloating();
            textInput.blur();
        }
    }, opts);

    // Blur → commit in offline mode
    if (!config.url) {
        $textInput.on('blur', () => {
            // Small delay so chip remove click can fire first
            setTimeout(() => {
                const val = textInput.value.trim();
                if (val && !stateRef.disabled && !stateRef.readonly) {
                    addChip(val, val, val);
                    textInput.value = '';
                }
            }, BLUR_DELAY);
        }, opts);
    }

    // Remote search on input
    if (config.url) {
        $textInput.on('input', () => {
            onSearchInput();
        }, opts);
    }

    // Chip remove (delegated)
    $container.on('click', (e) => {
        const removeBtn = e.target.closest(SEL.REMOVE);
        if (!removeBtn || stateRef.disabled || stateRef.readonly) return;
        e.stopPropagation();
        const chipEl = removeBtn.closest(SEL.CHIP);
        if (chipEl) {
            ctx.removeChipById(chipEl.dataset.id);
        }
    }, opts);

    return ac;
}

/**
 * Attach an outside-click listener that closes the suggestion dropdown.
 * Returns an AbortController for cleanup.
 *
 * @param {HTMLElement} container
 * @param {HTMLElement} floating
 * @param {Function} hideFloating — () => void
 * @returns {AbortController}
 */
export function attachOutsideClick(container, floating, hideFloating) {
    const ac = new AbortController();

    razyui(document).on('mousedown', (e) => {
        if (container.contains(e.target) || floating.contains(e.target)) return;
        hideFloating();
    }, { signal: ac.signal });

    return ac;
}
