/**
 * @fileoverview ClipBox component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/ClipBox.def
 */

import razyui from '../index.js';
import { PART } from './ClipBox/constants.js';

/**
 * The definition object for the ClipBox component.
 * Contains metadata, design tokens, state machine configuration, template slots, and custom element details.
 * 
 * @type {Object}
 */
export const ClipBoxDef = {
    /** @type {string} The name of the component. */
    name: 'ClipBox',
    
    /** @type {string} The custom element tag name. */
    tag: 'rui-clip-box',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    /**
     * Design tokens for styling the ClipBox component.
     * Defines CSS variables and their default values or references.
     */
    tokens: {
        prefix: 'cb',
        tokens: {
            'gap':             { ref: 'spacing.1',           description: 'Chip gap / container padding' },
            'radius':          { ref: 'radius.sm',           description: 'Container border radius' },
            'tag-radius':      { ref: 'radius.sm',           description: 'Tag border radius' },
            'font-size':       { ref: 'font.size-sm',        description: 'Font size' },
            'line-height':     { value: '1.25',              description: 'Line height' },
            'font-stack':      { ref: 'font.family',         description: 'Font family' },
            'accent':          { ref: 'color.accent',        description: 'Accent color' },
            'accent-subtle':   { ref: 'color.accent-subtle', description: 'Focus ring / subtle accent' },
            'bg':              { ref: 'color.bg',            description: 'Background' },
            'bg-hover':        { ref: 'color.bg-hover',      description: 'Hover background' },
            'bg-inset':        { ref: 'color.bg-inset',      description: 'Disabled / inset background' },
            'bg-raised':       { ref: 'color.bg-raised',     description: 'Readonly background' },
            'border':          { ref: 'color.border',        description: 'Border color' },
            'border-strong':   { ref: 'color.border-strong', description: 'Hover border' },
            'control-px':      { value: '0.75rem',           description: 'Control horizontal padding' },
            'control-py':      { value: '0.5rem',            description: 'Control vertical padding' },
            'danger':          { ref: 'color.danger',        description: 'Error / remove color' },
            'danger-subtle':   { ref: 'color.danger-subtle', description: 'Remove hover background' },
            'on-danger':       { ref: 'color.on-danger',     description: 'Text on danger background' },
            'shadow':          { ref: 'shadow.sm',           description: 'Tag shadow' },
            'shadow-lg':       { ref: 'shadow.lg',           description: 'Darkroom shadow' },
            'space-lg':        { ref: 'spacing.6',           description: 'Large spacing' },
            'space-md':        { ref: 'spacing.4',           description: 'Medium spacing' },
            'space-sm':        { ref: 'spacing.2',           description: 'Small spacing' },
            'space-xs':        { ref: 'spacing.1',           description: 'Extra-small spacing' },
            'text':            { ref: 'color.text',          description: 'Text color' },
            'text-muted':      { ref: 'color.text-muted',    description: 'Muted text' },
            'z-index':         { ref: 'z-index.popup',       description: 'Popup z-index' },
            'darkroom-z':      { ref: 'z-index.modal',       description: 'Darkroom overlay z-index' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    /**
     * State machine configuration for managing the clip box's interaction state.
     */
    states: {
        initial: 'idle',
        states: {
            idle:     { on: { EDIT: 'editing', DARKROOM: 'darkroom', DISABLE: 'disabled' } },
            editing:  { on: { COMMIT: 'idle', CANCEL: 'idle' } },
            darkroom: { on: { CLOSE: 'idle' } },
            disabled: { on: { ENABLE: 'idle' } },
        },
        effects: {
            /**
             * Effect triggered when entering the 'disabled' state.
             * Adds the 'is-disabled' class to the element.
             * 
             * @param {Object} ctx - The state machine context.
             */
            disabled(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-disabled');
            },
            /**
             * Effect triggered when exiting the 'disabled' state.
             * Removes the 'is-disabled' class from the element.
             * 
             * @param {Object} ctx - The state machine context.
             */
            'disabled:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-disabled');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    /**
     * Template slots defining the structure and classes of the clip box elements.
     */
    template: {
        slots: {
            root:     { element: 'div', classes: ['clip-box'] },
            tag:      { element: 'span', classes: ['clip-box-tag'] },
            input:    { element: 'input', classes: ['clip-box-input'] },
            darkroom: { element: 'div', classes: ['clip-box-darkroom'] },
            overlay:  { element: 'div', classes: ['clip-box-overlay'] },
        },
    },

    // ═══════════════════════════════════════
    //  Variants
    // ═══════════════════════════════════════
    /**
     * Available variants for the ClipBox component.
     */
    variants: {
        inline:     { description: 'Inline display mode' },
        compact:    { description: 'Compact single-line mode' },
        singleLine: { description: 'Single line (no wrap)' },
    },

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    /** @type {string[]} List of attributes to observe for changes. */
    observedAttrs: ['value', 'disabled', 'readonly', 'max-items', 'placeholder'],
    
    /** @type {Object<string, string>} Mapping of attribute names to property names. */
    attrMap: {
        value: 'value',
        disabled: 'disabled',
        readonly: 'readonly',
        'max-items': 'maxItems',
        placeholder: 'placeholder',
    },

    jitParts: {
        [PART.ROOT]: PART.ROOT,
        [PART.CHIP]: PART.CHIP,
        [PART.CHIP_LABEL]: PART.CHIP_LABEL,
        [PART.REMOVE]: PART.REMOVE,
        [PART.INPUT]: PART.INPUT,
        [PART.FLOATING]: PART.FLOATING,
        [PART.SUGGESTION]: PART.SUGGESTION,
        [PART.ERROR]: PART.ERROR,
        [PART.OVERFLOW]: PART.OVERFLOW,
        [PART.COMPACT_HINT]: PART.COMPACT_HINT,
        [PART.DARKROOM_OVERLAY]: PART.DARKROOM_OVERLAY,
        [PART.DARKROOM_PANEL]: PART.DARKROOM_PANEL,
        [PART.DARKROOM_HEADER]: PART.DARKROOM_HEADER,
        [PART.DARKROOM_TITLE]: PART.DARKROOM_TITLE,
        [PART.DARKROOM_CLOSE]: PART.DARKROOM_CLOSE,
        [PART.DARKROOM_BODY]: PART.DARKROOM_BODY,
    },

    styles: {},
};

export default ClipBoxDef;
