/**
 * @fileoverview ClipBox state — reactive state creation.
 * @module module/ClipBox/state
 */

/**
 * Create the reactive ClipBox state and wire effects.
 *
 * Returned stateSet exposes `[ref, setState]` plus `.effect()`.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @param {HTMLInputElement} inputEl — the original native `<input>`
 * @returns {[object, Function] & { effect: Function }} stateSet
 */
export function createReactiveState(stateFn, inputEl) {
    return stateFn({
        chips: [],           // [{ value, label }]
        disabled: inputEl.disabled,
        readonly: inputEl.hasAttribute('readonly'),
    });
}
