/**
 * @fileoverview ClipBox constants — CSS classes, selectors, SVG markup, defaults, magic numbers.
 * @module module/ClipBox/constants
 */

import { BLUR_CLOSE_DELAY_MS, DROPDOWN_GAP_PX, Z_DARKROOM, ICON_CLOSE_16_16 } from '../shared/tokens/index.js';
import Icons from '../Icons.js';
import { DARKROOM_STYLES } from '../shared/darkroomStyles.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:              'clip-box',
    INPUT:             'clip-box-input',
    CHIP:              'clip-box-chip',
    CHIP_LABEL:        'clip-box-chip-label',
    REMOVE:            'clip-box-remove',
    FLOATING:          'clip-box-floating',
    SUGGESTION:        'clip-box-suggestion',
    OVERFLOW:          'clip-box-overflow',
    COMPACT_HINT:      'clip-box-compact-hint',
    ERROR:             'clip-box-error',
    GHOST:             'clip-box-ghost',
    DARKROOM_OVERLAY:  'clip-box-darkroom-overlay',
    DARKROOM_PANEL:    'clip-box-darkroom-panel',
    DARKROOM_HEADER:   'clip-box-darkroom-header',
    DARKROOM_TITLE:    'clip-box-darkroom-title',
    DARKROOM_CLOSE:    'clip-box-darkroom-close',
    DARKROOM_BODY:     'clip-box-darkroom-body',
});

/** State / modifier class names */
export const STATE_CLS = Object.freeze({
    INLINE:           'is-inline',
    CELL:             'is-cell',
    singleLine:      'is-single-line',
    compact:          'is-compact',
    DISABLED:         'is-disabled',
    READONLY:         'is-readonly',
    ERROR:            'is-error',
    INVALID:          'is-invalid',
    ADDED:            'is-added',
    OVERFLOW_HIDDEN:  'is-overflow-hidden',
});

/** DOM selectors */
export const SEL = Object.freeze({
    CHIP:             '.clip-box-chip',
    CHIP_LABEL:       '.clip-box-chip-label',
    REMOVE:           '.clip-box-remove',
    INPUT:            '.clip-box-input',
    ERROR:            '.clip-box-error',
    OVERFLOW_HIDDEN:  '.clip-box-chip.is-overflow-hidden',
});

/** razyui.spell() incantation patterns */
export const SPELL = Object.freeze({
    CONTAINER: 'div.clip-box[data-slot=container](input.clip-box-input[data-slot=input])',
    FLOATING:  'div.clip-box-floating[data-slot=floating]',
    CHIP:      'span.clip-box-chip[data-slot=chip](span.clip-box-chip-label[data-slot=chip-label],button.clip-box-remove[data-slot=chip-remove])',
});

/** SVG markup strings */
export const SVG = Object.freeze({
    REMOVE: Icons.svg('x', { size: 12, strokeWidth: 1.6 }),
    COMPACT_HINT: Icons.svg('square-pen', { size: 12, strokeWidth: 1.4 }),
    DARKROOM_CLOSE: ICON_CLOSE_16_16,
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    separator:        ',',
    minLength:       2,
    debounce:         400,
    max:              0,
    singleLine:      false,
    compact:          false,
    allowDuplicate:  false,
    placeholder:      '',
    dropdownGap:     DROPDOWN_GAP_PX,
});

/** Magic numbers */
export const BLUR_DELAY = BLUR_CLOSE_DELAY_MS;
export const DARKROOM_Z_INDEX = String(Z_DARKROOM);

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('ClipBox', {
    ROOT        : { class: 'clip-box', aliases: ['root', 'container', 'clip-box'] },
    CHIP        : { class: 'clip-box-chip', aliases: ['chip', 'tag'] },
    CHIP_LABEL  : { class: 'clip-box-chip-label' },
    REMOVE      : { class: 'clip-box-remove' },
    INPUT       : { class: 'clip-box-input' },
    FLOATING    : { class: 'clip-box-floating' },
    SUGGESTION  : { class: 'clip-box-suggestion' },
    ERROR       : { class: 'clip-box-error' },
    OVERFLOW    : { class: 'clip-box-overflow' },
    COMPACT_HINT: { class: 'clip-box-compact-hint' },
    DARKROOM_OVERLAY: { class: 'clip-box-darkroom-overlay' },
    DARKROOM_PANEL: { class: 'clip-box-darkroom-panel' },
    DARKROOM_HEADER: { class: 'clip-box-darkroom-header' },
    DARKROOM_TITLE: { class: 'clip-box-darkroom-title' },
    DARKROOM_CLOSE: { class: 'clip-box-darkroom-close' },
    DARKROOM_BODY: { class: 'clip-box-darkroom-body' },
});

PART.ROOT.jit     = 'relative flex flex-wrap items-center gap-[var(--cb-gap)] [border:1px_solid_var(--cb-border)] rounded-[var(--cb-radius)] [padding:var(--cb-gap)_var(--cb-control-px)] cursor-text bg-[var(--cb-bg)] [font-family:inherit] text-[var(--cb-font-size)] [line-height:var(--cb-line-height)] [min-height:calc(var(--cb-font-size)*var(--cb-line-height)_+_var(--cb-control-py)*2_+_2px)] hover:[border-color:var(--cb-border-strong)] focus-within:[border-color:var(--cb-accent)] focus-within:[box-shadow:0_0_0_2px_var(--cb-accent-subtle)] {is-disabled}:bg-[var(--cb-bg-inset)] {is-disabled}:[cursor:not-allowed] {is-disabled}:[opacity:.6] {is-disabled}:hover:[border-color:var(--cb-border)] {is-readonly}:cursor-default {is-readonly}:bg-[var(--cb-bg-raised)] {is-compact}:flex-nowrap {is-compact}:overflow-hidden {is-compact}:cursor-pointer {is-compact}:[padding-right:28px] {is-single-line}:flex-nowrap {is-single-line}:[overflow-x:auto] {is-single-line}:[overflow-y:hidden] {is-single-line}:[scrollbar-width:none]';
PART.CHIP.jit     = 'inline-flex items-center gap-[4px] bg-[var(--cb-bg-hover)] [border:1px_solid_var(--cb-border)] rounded-[3px] [padding:1px_6px] text-[.78rem] [line-height:1.5] fg-[var(--cb-text)] text-nowrap motion-clip-box-in';
PART.CHIP_LABEL.jit = '[max-width:200px] overflow-hidden [text-overflow:ellipsis]';
PART.REMOVE.jit   = 'flex items-center justify-center shrink-0 [appearance:none] [border:none] [background:none] cursor-pointer fg-[var(--cb-text-muted)] [padding:0] [margin:0] [font-size:inherit] [line-height:1] rounded-[2px] hover:fg-[var(--cb-danger)] hover:bg-[var(--cb-danger-subtle)] ^{is-compact}:hidden';
PART.INPUT.jit    = '[flex:1_1_80px] min-w-[80px] [border:none] [outline:none] [background:transparent] [box-shadow:none] [border-radius:0] [font-family:inherit] [font-size:inherit] [line-height:inherit] fg-[var(--cb-text)] [padding:var(--cb-control-py)_0] [width:auto] placeholder:fg-[var(--cb-text-muted)] ^{is-compact}:hidden';
PART.FLOATING.jit = 'absolute bg-[var(--cb-bg)] [border:1px_solid_var(--cb-border)] rounded-[var(--cb-radius)] [box-shadow:var(--cb-shadow-lg)] [max-height:240px] overflow-y-auto [font-family:inherit] text-[var(--cb-font-size)]';
PART.SUGGESTION.jit = '[padding:var(--cb-control-py)_var(--cb-control-px)] cursor-pointer [border-bottom:1px_solid_var(--cb-border)] [line-height:1.5] hover:bg-[var(--cb-bg-hover)] last:[border-bottom:none] {is-added}:[opacity:.4] {is-added}:cursor-default {is-added}:hover:[background:rgba(0,0,0,0)]';
PART.ERROR.jit    = 'absolute [left:0] [top:100%] [margin-top:4px] [padding:var(--cb-gap)_var(--cb-space-sm)] text-[.75rem] [line-height:1.3] fg-[var(--cb-on-danger)] bg-[var(--cb-danger)] rounded-[var(--cb-radius)] text-nowrap [z-index:10] pointer-events-none';
PART.OVERFLOW.jit = 'inline-flex items-center text-nowrap text-[.72rem] fg-[var(--cb-text-muted)] [padding:1px_6px] shrink-0 pointer-events-none';
PART.COMPACT_HINT.jit = 'absolute [right:6px] [top:0] [bottom:0] [margin:auto] [display:none] items-center justify-center [height:fit-content] fg-[var(--cb-text-muted)] pointer-events-none [opacity:.45] ^{is-compact}:flex';
PART.DARKROOM_OVERLAY.jit = DARKROOM_STYLES.OVERLAY;
PART.DARKROOM_PANEL.jit = DARKROOM_STYLES.PANEL;
PART.DARKROOM_HEADER.jit = DARKROOM_STYLES.HEADER;
PART.DARKROOM_TITLE.jit = 'fw-600 text-[.875rem] fg-[var(--rui-text)]';
PART.DARKROOM_CLOSE.jit = DARKROOM_STYLES.CLOSE;
PART.DARKROOM_BODY.jit = DARKROOM_STYLES.BODY + ' [padding:0.5rem_1rem]';