/**
 * @fileoverview ClipBox component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, selectors, SVG markup, defaults
 *   helpers.js   — parsing, mapping, normalisation utilities
 *   state.js     — reactive state creation
 *   view.js      — DOM setup / teardown + effects + rendering
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/ClipBox
 */

import { default as razyui } from '../../index.js';
import { sharedResizeObserver } from '../shared/SharedResizeObserver.js';

import { DEFAULTS, STATE_CLS, CLS, SEL }                       from './constants.js';
import { parseInitialParts, normalizeChipItems }               from './helpers.js';
import { createReactiveState }                                 from './state.js';
import {
    buildDOM, wireEffects, renderChips as renderChipsDom,
    showError, showSuggestions, hideFloating as hideFloatingView,
    updateOverflow as updateOverflowView,
    openDarkroom as openDarkroomView, closeDarkroom as closeDarkroomView,
    destroyDOM,
}                                                              from './view.js';
import { bindEvents }                                          from './events.js';
import { attachOutsideClick }                                   from '../shared/outsideClick.js';
import { emitEvent }                                            from '../shared/emitEvent.js';

/**
 * ClipBox — v2 modular rewrite
 *
 * A tag/chip input component. Enhances a native <input> into a container
 * where values become removable chip badges.
 *
 * Two modes:
 *   - **Offline** (no `url`): type freely, press Enter to commit a chip.
 *   - **Remote** (`url` set): type-ahead search with floating suggestion list,
 *     click a result to add it as a chip.
 *
 * Reactive state via razyui.state(); property setters on getControl().
 *
 * Features:
 *   - Manual tag creation (Enter / blur)
 *   - Remote search with debounced fetch + suggestion dropdown
 *   - Backspace to remove last chip
 *   - Removable chip (✕ button)
 *   - Duplicate prevention
 *   - Max chip limit
 *   - Separator-based initial value parsing (e.g. "a, b, c")
 *   - Programmatic add / remove / clear via API + getControl()
 *   - Validation hook (onBeforeAdd) — return false to block, string to show error
 *   - Callbacks: onAdd, onRemove, onChange
 *   - States: disabled, readonly
 *
 * @param {string|Element} selector — CSS selector or Element for an <input>
 * @param {object} config
 * @param {string}   [config.url]           — remote search endpoint (GET ?keyword=…)
 * @param {string}   [config.separator]     — separator for parsing initial value (default ",")
 * @param {number}   [config.minLength]     — min chars before remote search fires (default 2)
 * @param {number}   [config.debounce]      — debounce ms for remote search (default 400)
 * @param {number}   [config.max]           — max number of chips (0 = unlimited, default 0)
 * @param {boolean}  [config.singleLine]    — force single-line layout (no wrapping, horizontal scroll)
 * @param {boolean}  [config.allowDuplicate] — allow duplicate values (default false)
 * @param {string}   [config.placeholder]   — placeholder text for the input
 * @param {function} [config.onBeforeAdd]   — (id, value, label) => true | false | "error msg"
 * @param {function} [config.onAdd]         — (id, value, label) => void
 * @param {function} [config.onRemove]      — (id, value, label) => void
 * @param {function} [config.onChange]       — (chips:[{id,value,label}]) => void
 * @param {function} [config.onRenderSuggestion] — (item:object) => string (HTML for suggestion row)
 * @param {function} [config.mapId]         — (item:object) => string  — extract unique id from remote item
 * @param {function} [config.mapValue]      — (item:object) => string  — extract value from remote item
 * @param {function} [config.mapLabel]      — (item:object) => string  — extract label from remote item
 */
const ClipBox = class {
    #input = null;          // original <input> Element ref
    #destroyed = false;
    #container = null;      // .clip-box DOM element
    #textInput = null;      // inner <input> for typing
    #floating = null;       // suggestion dropdown DOM element
    #config = {};
    #stateRef = null;
    #setState = null;
    #outsideAC = null; // outside-click cleanup
    #searchTimer = null;    // debounce timer for remote search
    #fetchAC = null;// AbortController for in-flight fetch
    #darkroom = null;       // darkroom overlay DOM element
    #overflowBadge = null;  // "+N" badge element
    #compactAnchor = null;  // placeholder marking original position
    #ghost = null;          // ghost element preserving layout while darkroom open
    #eventAC = null;        // AbortController for centralised event cleanup
    #resizeObsEl = null;    // Element tracked by shared ResizeObserver

    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve JIT spacing tokens
        this.#config.dropdownGap = razyui.JIT.TOKEN.spacePx(this.#config.dropdownGap);

        // Resolve the native <input>
        if (typeof selector === 'string') {
            this.#input = razyui(selector);
        } else {
            this.#input = razyui(selector);
        }

        if (!this.#input.length || !this.#input.is('input')) {
            console.warn('ClipBox: <input> element not found \u2192', selector);
            return;
        }

        const inputEl = this.#input[0];
        if (config.name) inputEl.name = config.name;

        // ── Build DOM ──
        const { container, textInput, floating, overflowBadge, compactAnchor } =
            buildDOM(razyui.spell, inputEl, this.#config);

        this.#container = container;
        this.#textInput = textInput;
        this.#floating = floating;
        this.#overflowBadge = overflowBadge;
        this.#compactAnchor = compactAnchor;

        // ── Reactive state ──
        const stateSet = createReactiveState(razyui.state, inputEl);
        const [stateRef, setState] = stateSet;
        this.#stateRef = stateRef;
        this.#setState = setState;

        // ── Effects ──
        wireEffects(stateSet, {
            container,
            textInput,
            inputEl,
            config: this.#config,
            renderChips: () => this.#renderChips(),
            updateOverflow: () => this.#updateOverflow(),
        });

        // ── Events ──
        this.#eventAC = bindEvents({
            container,
            textInput,
            stateRef,
            setState,
            config:           this.#config,
            addChip:          (id, v, l) => this.#addChip(id, v, l),
            fireRemove:       (chip) => this.#fireRemove(chip),
            fireChange:       () => this.#fireChange(),
            hideFloating:     () => this.#hideFloating(),
            onSearchInput:    () => this.#onSearchInput(),
            openDarkroom:     () => this.#openDarkroom(),
            closeDarkroom:    () => this.#closeDarkroom(),
            getDarkroom:      () => this.#darkroom,
            removeChipById:   (id) => this.#removeChipById(id),
        });

        // ── Compact overflow observer (shared pool) ──
        if (this.#config.compact) {
            this.#resizeObsEl = container;
            sharedResizeObserver.observe(container, () => {
                if (!this.#darkroom) this.#updateOverflow();
            });
        }

        // ── Parse initial value ──
        this.#parseInitialValue();
    }

    // ────────────────────────────────────────────
    // Private methods
    // ────────────────────────────────────────────

    /** Parse comma-separated initial input value into chips. */
    #parseInitialValue() {
        const inputEl = this.#input[0];
        const raw = inputEl.getAttribute('value') || '';
        const chips = parseInitialParts(raw, this.#config.separator, this.#config.allowDuplicate);
        if (chips.length) {
            this.#setState({ chips });
            this.#fireChange();
        }
    }

    /**
     * Add a chip with validation. Returns true if added.
     *
     * @param {string} id — unique identifier
     * @param {string} [value] — value (defaults to id)
     * @param {string} [label] — display label (defaults to value)
     * @returns {boolean}
     */
    #addChip(id, value, label) {
        const state = this.#stateRef;
        value = value || id;
        label = label || value;

        // Max check
        if (this.#config.max > 0 && state.chips.length >= this.#config.max) {
            return false;
        }

        // Duplicate check (by unique id)
        if (!this.#config.allowDuplicate && state.chips.some(c => c.id === id)) {
            return false;
        }

        // onBeforeAdd validation
        if (typeof this.#config.onBeforeAdd === 'function') {
            const result = this.#config.onBeforeAdd.call(this, id, value, label);
            if (result === false) return false;
            if (typeof result === 'string') {
                // Show error briefly
                showError(this.#container, this.#textInput, result);
                return false;
            }
        }

        const chips = [...state.chips, { id, value, label }];
        this.#setState({ chips });

        if (typeof this.#config.onAdd === 'function') {
            this.#config.onAdd.call(this, id, value, label);
        }
        this.#fireChange();
        return true;
    }

    /** Remove a chip by its unique id. */
    #removeChipById(id) {
        const state = this.#stateRef;
        const idx = state.chips.findIndex(c => c.id === id);
        if (idx < 0) return;
        const removed = state.chips[idx];
        const chips = state.chips.filter((_, i) => i !== idx);
        this.#setState({ chips });
        this.#fireRemove(removed);
        this.#fireChange();
    }

    /** Render chip DOM elements. */
    #renderChips() {
        renderChipsDom(
            razyui.spell,
            this.#container,
            this.#stateRef.chips,
            this.#textInput,
            this.#config,
        );
    }

    /** Fire onRemove callback. */
    #fireRemove(chip) {
        emitEvent(this.#container, 'remove', { id: chip.id, value: chip.value, label: chip.label });
        if (typeof this.#config.onRemove === 'function') {
            this.#config.onRemove.call(this, chip.id, chip.value, chip.label);
        }
    }

    /** Fire onChange callback with full chips array. */
    #fireChange() {
        const chips = [...this.#stateRef.chips];
        this.#input[0].value = chips.map(c => c.value).join(this.#config.separator || ',');
        emitEvent(this.#container, 'change', { value: chips, chips });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, chips);
        }
    }

    // ── Remote search ──

    /** Handle input changes for remote search. */
    #onSearchInput() {
        const query = this.#textInput.value.trim();
        if (query.length < this.#config.minLength) {
            this.#hideFloating();
            return;
        }

        clearTimeout(this.#searchTimer);
        this.#searchTimer = setTimeout(() => {
            this.#fetchSuggestions(query);
        }, this.#config.debounce);
    }

    /** Fetch suggestions from remote endpoint or callback. */
    async #fetchSuggestions(query) {
        // Abort previous request
        this.#fetchAC?.abort();
        this.#fetchAC = new AbortController();

        try {
            let data;
            const src = this.#config.url;

            if (razyui.isFn(src)) {
                // Callback mode — the function returns a result (or promise)
                data = await src(query);
            } else {
                // XHR mode — standard fetch
                const url = src + (src.includes('?') ? '&' : '?') + 'keyword=' + encodeURIComponent(query);
                const response = await fetch(url, { signal: this.#fetchAC.signal });
                data = await response.json();
            }

            if (Array.isArray(data) && data.length > 0) {
                this.#showSuggestions(data);
            } else {
                this.#hideFloating();
            }
        } catch (e) {
            if (e.name !== 'AbortError') {
                this.#hideFloating();
            }
        }
    }

    /** Render the suggestion dropdown. */
    #showSuggestions(items) {
        showSuggestions({
            floating:           this.#floating,
            container:          this.#container,
            config:             this.#config,
            stateRef:           this.#stateRef,
            darkroom:           this.#darkroom,
            addChip:            (id, v, l) => this.#addChip(id, v, l),
            textInput:          this.#textInput,
            attachOutsideClick: () => this.#attachOutsideClick(),
        }, items);
    }

    /** Hide suggestion dropdown. */
    #hideFloating() {
        hideFloatingView(this.#floating, () => this.#detachOutsideClick());
    }

    /** Attach outside-click to close suggestions. */
    #attachOutsideClick() {
        this.#detachOutsideClick();
        this.#outsideAC = attachOutsideClick(
            this.#container,
            this.#floating,
            () => this.#hideFloating(),
        );
    }

    /** Remove outside-click listener. */
    #detachOutsideClick() {
        this.#outsideAC?.abort();
        this.#outsideAC = null;
    }

    // ── Compact mode ──

    /** Recalculate which chips are visible and update the overflow badge. */
    #updateOverflow() {
        if (!this.#config.compact || this.#darkroom) return;
        updateOverflowView(this.#container, this.#overflowBadge, !!this.#darkroom);
    }

    /** Open darkroom modal editor for chip editing. */
    #openDarkroom() {
        if (this.#darkroom) return;

        const result = openDarkroomView({
            container:     this.#container,
            textInput:     this.#textInput,
            config:        this.#config,
            overflowBadge: this.#overflowBadge,
            compactAnchor: this.#compactAnchor,
        });

        this.#darkroom = result.overlay;
        this.#ghost = result.ghost;

        // Darkroom-specific event wiring
        result.closeBtn.on('click', () => this.#closeDarkroom());
        result.overlay.on('mousedown', (e) => {
            if (e.target === result.overlay[0]) this.#closeDarkroom();
        });
    }

    /** Close darkroom and return to compact view. */
    #closeDarkroom() {
        if (!this.#darkroom) return;

        closeDarkroomView({
            container:     this.#container,
            config:        this.#config,
            ghost:         this.#ghost,
            compactAnchor: this.#compactAnchor,
            overlay:       this.#darkroom,
        });

        this.#darkroom = null;
        this.#ghost = null;

        // Recalculate overflow
        requestAnimationFrame(() => this.#updateOverflow());
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    /** Get all chip ids as an array of strings. */
    getValues() {
        return this.#stateRef.chips.map(c => c.id);
    }

    /** Get all chips as [{id, value, label}]. */
    getChips() {
        return [...this.#stateRef.chips];
    }

    /** Programmatically add a chip. */
    addChip(id, value, label) {
        return this.#addChip(id, value || id, label || value || id);
    }

    /** Programmatically remove a chip by id. */
    removeChip(id) {
        this.#removeChipById(id);
    }

    /** Remove all chips. */
    clear() {
        const old = [...this.#stateRef.chips];
        this.#setState({ chips: [] });
        for (const chip of old) this.#fireRemove(chip);
        this.#fireChange();
    }

    /** Set chips from an array of {value, label} or plain strings. */
    setChips(items) {
        const chips = normalizeChipItems(items);
        this.#setState({ chips });
        this.#fireChange();
    }

    /** Enable or disable the component. */
    setDisabled(disabled) {
        this.#setState({ disabled: !!disabled });
        this.#input.prop('disabled', !!disabled);
        this.#container.setAttribute('aria-disabled', String(!!disabled));
    }

    setInvalid(invalid) {
        this.#container.classList.toggle(STATE_CLS.INVALID, !!invalid);
        this.#container[invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#textInput?.focus(); }
    blur()  { this.#textInput?.blur(); }

    /** Toggle readonly state. */
    setReadonly(readonly) {
        this.#setState({ readonly: !!readonly });
        this.#container.setAttribute('aria-readonly', String(!!readonly));
    }

    /**
     * Return a control object with property setters.
     *   ctrl.values         — get string[] (ids)
     *   ctrl.chips          — get/set [{id,value,label}]
     *   ctrl.disabled       — get/set boolean
     *   ctrl.readonly       — get/set boolean
     *   ctrl.add(id, v, l)  — add a chip
     *   ctrl.remove(id)     — remove a chip by id
     *   ctrl.clear()        — remove all chips
     */
    getControl() {
        const self = this;
        return {
            get values() { return self.getValues(); },
            get chips() { return self.getChips(); },
            set chips(v) { self.setChips(v); },
            get disabled() { return self.#stateRef.disabled; },
            set disabled(v) { self.setDisabled(v); },
            get readonly() { return self.#stateRef.readonly; },
            set readonly(v) { self.setReadonly(v); },
            add:    (id, value, label) => self.addChip(id, value, label),
            remove: (id) => self.removeChip(id),
            clear:  () => self.clear(),
            get max() { return self.#config.max; },
            set max(v) { self.#config.max = Math.max(0, parseInt(v) || 0); },
            get singleLine() { return self.#config.singleLine; },
            set singleLine(v) {
                self.#config.singleLine = !!v;
                razyui(self.#container).toggleClass(STATE_CLS.SINGLE_LINE, !!v);
            },
            get compact() { return self.#config.compact; },
            set compact(v) {
                self.#config.compact = !!v;
                razyui(self.#container).toggleClass(STATE_CLS.COMPACT, !!v);
                if (v) {
                    if (!self.#overflowBadge) {
                        const badge = razyui.el('span', { className: CLS.OVERFLOW });
                        badge.css('display', 'none');
                        self.#overflowBadge = badge;
                        razyui(self.#container).append(badge[0]);
                    }
                    if (!self.#compactAnchor) {
                        const anchor = razyui.el('span');
                        anchor.css('display', 'none');
                        self.#container.parentNode.insertBefore(anchor[0], self.#container.nextSibling);
                        self.#compactAnchor = anchor;
                    }
                    requestAnimationFrame(() => self.#updateOverflow());
                } else {
                    if (self.#overflowBadge) self.#overflowBadge.css('display', 'none');
                    razyui(self.#container).find(SEL.OVERFLOW_HIDDEN)
                        .each(c => razyui(c).removeClass(STATE_CLS.OVERFLOW_HIDDEN));
                }
            },
            get required() { return self.#input[0].required; },
            set required(v) { self.#input[0].required = !!v; self.#container.setAttribute('aria-required', String(!!v)); },
            openDarkroom:      () => self.#openDarkroom(),
            closeDarkroom:     () => self.#closeDarkroom(),
            setInvalid:        (v) => self.setInvalid(v),
            checkValidity:     () => self.#input[0].checkValidity(),
            reportValidity:    () => self.#input[0].reportValidity(),
            setCustomValidity: (m) => { self.#input[0].setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#container.getAttribute('aria-label'); },
            set label(v) { v ? self.#container.setAttribute('aria-label', v) : self.#container.removeAttribute('aria-label'); },
            get labelledby() { return self.#container.getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container.setAttribute('aria-labelledby', v) : self.#container.removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container.getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#container.setAttribute('aria-describedby', v) : self.#container.removeAttribute('aria-describedby'); },
            focus: () => self.focus(),
            blur:  () => self.blur(),
            get name() { return self.#input[0].name; },
            set name(v) { self.#input[0].name = v ?? ''; },
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Tear down — restore native <input>. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        if (this.#darkroom) this.#closeDarkroom();
        this.#hideFloating();
        clearTimeout(this.#searchTimer);
        this.#fetchAC?.abort();
        this.#eventAC?.abort();
        if (this.#resizeObsEl) { sharedResizeObserver.unobserve(this.#resizeObsEl); this.#resizeObsEl = null; }

        destroyDOM({
            floating:      this.#floating,
            container:     this.#container,
            ghost:         this.#ghost,
            compactAnchor: this.#compactAnchor,
            inputEl:       this.#input[0],
        });
    }
};

export default ClipBox;
